import{_ as e,c as t,o as a,d as o}from"./app.0d14d0b2.js";const g='{"title":"DIY \u0430\u043A\u0430\u0434\u0435\u043C\u0438\u044F","description":"","frontmatter":{"title":"DIY \u0430\u043A\u0430\u0434\u0435\u043C\u0438\u044F","subtitle":"\u041E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u0430\u044F \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F","date":"2014-11-19","icon":"diy-logo-color.png","cover":"cover.jpg","tel":"+7 (925) 483-56-90","url":"https://diy-academy.ru","email":"mail@diy-academy.ru","address":"\u041C\u0430\u043B\u0430\u044F \u0421\u0435\u043C\u0435\u043D\u043E\u0432\u0441\u043A\u0430\u044F, 5\u04411","place":"\u043C. \u0421\u0435\u043C\u0435\u043D\u043E\u0432\u0441\u043A\u0430\u044F","city":"\u0433. \u041C\u043E\u0441\u043A\u0432\u0430","coord":[55.784906234562854,37.70755917002208],"facebook":"diyacademybosch","instagram":"diyacademy","status":"open"},"headers":[{"level":3,"title":"\u0418\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B","slug":"\u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B"},{"level":3,"title":"\u041C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u044B","slug":"\u043C\u0430\u0442\u0435\u0440\u0438\u0430n\u044B"},{"level":3,"title":"\u0423\u0441\u043B\u043E\u0432\u0438\u044F","slug":"\u0443\u0441n\u043E\u0432\u0438\u044F"}],"relativePath":"workshop/catalog/diy-academy/index.md"}',r={},i=o('<p>DIY (do it yourself) \u2013 \u044D\u0442\u043E \u0441\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0435 \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435 \u0442\u0435\u0445, \u043A\u0442\u043E \u043B\u044E\u0431\u0438\u0442 \u0440\u0430\u0431\u043E\u0442\u0430\u0442\u044C \u0440\u0443\u043A\u0430\u043C\u0438. \u041C\u044B - \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u0430\u044F \u0448\u043A\u043E\u043B\u0430 \u0441 \u043A\u0443\u0440\u0441\u0430\u043C\u0438 \u0438 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F \u0434\u043B\u044F \u0432\u0430\u0448\u0438\u0445 \u044D\u043A\u0441\u043F\u0435\u0440\u0438\u043C\u0435\u043D\u0442\u043E\u0432/\u0445\u043E\u0431\u0431\u0438. DIY \u0410\u043A\u0430\u0434\u0435\u043C\u0438\u044F \u2014 \u043A\u043E\u043C\u0444\u043E\u0440\u0442\u043D\u0430\u044F \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F \u0441 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u044E\u0449\u0438\u043C\u0438 \u043C\u0430\u0441\u0442\u0435\u0440\u0430\u043C\u0438, \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u043C, \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u0430\u043C\u0438 \u0438 \u043F\u0440\u043E\u0440\u0430\u0431\u043E\u0442\u0430\u043D\u043D\u044B\u043C\u0438 \u043F\u0440\u043E\u0433\u0440\u0430\u043C\u043C\u0430\u043C\u0438 \u0434\u043B\u044F \u043D\u043E\u0432\u0438\u0447\u043A\u043E\u0432 \u0438 \u0442\u0435\u0445, \u043A\u0442\u043E \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u0435\u0442 \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u043E\u0435 \u0434\u0435\u043B\u043E \u0432\u0440\u0435\u043C\u044F \u043E\u0442 \u0432\u0440\u0435\u043C\u0435\u043D\u0438. \u041F\u043E\u043C\u043E\u0433\u0430\u0435\u043C \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0445\u043E\u0431\u0431\u0438 \u043F\u0440\u043E\u0444\u0435\u0441\u0441\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u043C \u0445\u0435\u043D\u0434\u043C\u0435\u0439\u0434\u043E\u043C. \u041E\u0442\u043B\u0438\u0447\u043D\u044B\u0439 \u0441\u0442\u0430\u0440\u0442, \u0435\u0441\u043B\u0438 \u0432\u044B \u0445\u043E\u0442\u0438\u0442\u0435 \u0438\u0441\u043F\u044B\u0442\u0430\u0442\u044C \u0441\u0435\u0431\u044F, \u043F\u043E\u043D\u044F\u0442\u044C, \u043D\u0430\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0431\u043B\u0438\u0437\u043E\u043A \u0432\u0430\u043C \u0448\u0443\u043C \u0444\u0440\u0435\u0437\u0435\u0440\u0430 \u0438 \u0448\u043B\u0438\u0444\u043C\u0430\u0448\u0438\u043D\u043A\u0438.</p><blockquote><p>\u0417\u0434\u0435\u0441\u044C \u043A\u0430\u0436\u0434\u044B\u0439 \u043C\u043E\u0436\u0435\u0442 \u0432\u0437\u044F\u0442\u044C \u0432 \u0430\u0440\u0435\u043D\u0434\u0443 \u0432\u0435\u0440\u0441\u0442\u0430\u043A \u0438 \u0432\u043E\u043F\u043B\u043E\u0442\u0438\u0442\u044C \u0441\u0432\u043E\u044E \u043C\u0435\u0447\u0442\u0443 \u0432 \u0434\u0435\u0440\u0435\u0432\u0435 \u043F\u0440\u0438 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u043A\u0435 \u0434\u0438\u0437\u0430\u0439\u043D\u0435\u0440\u043E\u0432 \u0438 \u0441\u0442\u043E\u043B\u044F\u0440\u043E\u0432. \u041C\u0435\u0447\u0442\u044B \u0443 \u0432\u0441\u0435\u0445, \u043A\u043E\u043D\u0435\u0447\u043D\u043E, \u0440\u0430\u0437\u043D\u044B\u0435. \u041A\u0442\u043E-\u0442\u043E \u043F\u0440\u043E\u0441\u0442\u043E \u0445\u043E\u0447\u0435\u0442 \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0441\u0442\u0435\u043B\u043B\u0430\u0436, \u043A\u043E\u043C\u0443-\u0442\u043E \u0434\u0430\u0432\u043D\u043E \u0441\u043D\u0438\u0442\u0441\u044F \u0440\u0430\u0431\u043E\u0447\u0438\u0439 \u0441\u0442\u043E\u043B, \u0437\u0430 \u043A\u043E\u0442\u043E\u0440\u044B\u043C \u043B\u0435\u0433\u043A\u043E \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u0430\u0447\u0438\u0432\u0430\u0442\u044C\u0441\u044F, \u043A\u0442\u043E-\u0442\u043E \u043C\u0435\u0447\u0442\u0430\u0435\u0442 \u043F\u043E\u0441\u0442\u0440\u043E\u0438\u0442\u044C \u0432\u043E \u0434\u0432\u043E\u0440\u0435 \u0440\u0430\u043C\u043F\u0443 \u0434\u043B\u044F \u0441\u043A\u0435\u0439\u0442\u0431\u043E\u0440\u0434\u0430, \u0430 \u043A\u0442\u043E-\u0442\u043E \u043A\u043E\u043D\u0441\u0442\u0440\u0443\u0438\u0440\u0443\u0435\u0442 \u0432\u0438\u0442\u0440\u0438\u043D\u0443 \u0444\u0443\u0434 \u0441\u0442\u0430\u0440\u0442\u0430\u043F\u0430.</p><p>\u041C\u044B \u0441 \u0440\u0430\u0434\u043E\u0441\u0442\u044C\u044E \u043F\u043E\u043C\u043E\u0436\u0435\u043C \u0432\u0430\u043C \u0441\u043E\u0437\u0434\u0430\u0442\u044C \u0434\u0438\u0437\u0430\u0439\u043D \u0436\u0435\u043B\u0430\u043D\u043D\u043E\u0433\u043E \u043E\u0431\u044A\u0435\u043A\u0442\u0430 \u0438 \u0432\u043C\u0435\u0441\u0442\u0435 \u043F\u043E\u0434\u0443\u043C\u0430\u0435\u043C \u043D\u0430\u0434 \u043A\u043E\u043D\u0441\u0442\u0440\u0443\u043A\u0446\u0438\u0435\u0439. \u0410 \u0435\u0441\u043B\u0438 \u0443 \u0432\u0430\u0441 \u043D\u0435 \u0445\u0432\u0430\u0442\u0430\u0435\u0442 \u043D\u0430\u0432\u044B\u043A\u043E\u0432, \u0442\u043E \u043C\u043E\u0436\u043D\u043E \u0437\u0430\u043F\u0438\u0441\u0430\u0442\u044C\u0441\u044F \u043D\u0430 \xAB\u041A\u0443\u0440\u0441 \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u043E\u0433\u043E \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u0442\u0432\u0430\xBB.</p></blockquote><h3 id="\u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B" tabindex="-1">\u0418\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B <a class="header-anchor" href="#\u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B" aria-hidden="true">#</a></h3><p>\u0412\u0441\u044F \u043B\u0438\u043D\u0435\u0439\u043A\u0430\xA0\u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432 \u0411\u043E\u0448.</p><h3 id="\u043C\u0430\u0442\u0435\u0440\u0438\u0430n\u044B" tabindex="-1">\u041C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u044B <a class="header-anchor" href="#\u043C\u0430\u0442\u0435\u0440\u0438\u0430n\u044B" aria-hidden="true">#</a></h3><p>\u041D\u0430 \u043F\u043B\u043E\u0449\u0430\u0434\u043A\u0435 \u0432\u0441\u0435\u0433\u0434\u0430 \u043C\u043E\u0436\u043D\u043E \u043A\u0443\u043F\u0438\u0442\u044C \u043F\u043E \u0440\u044B\u043D\u043E\u0447\u043D\u043E\u0439 \u0441\u0435\u0431\u0435\u0441\u0442\u043E\u0438\u043C\u043E\u0441\u0442\u0438 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442\u043D\u044B\u0439 \u043D\u0430\u0431\u043E\u0440 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u043E\u0432, \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 \u043A\u0440\u0435\u043F\u0435\u0436\u0430, \u043A\u0440\u0430\u0441\u043E\u043A \u0438 \u043B\u0430\u043A\u043E\u0432.</p><h3 id="\u0443\u0441n\u043E\u0432\u0438\u044F" tabindex="-1">\u0423\u0441\u043B\u043E\u0432\u0438\u044F <a class="header-anchor" href="#\u0443\u0441n\u043E\u0432\u0438\u044F" aria-hidden="true">#</a></h3><ul><li><strong>\u0411\u0410\u0417\u041E\u0412\u042B\u0419 \u0422\u0410\u0420\u0418\u0424 \u2013\xA01000 \u0440\u0443\u0431\u043B\u0435\u0439 3 \u0447\u0430\u0441\u0430</strong> \u042D\u0442\u043E \u043E\u043F\u0442\u0438\u043C\u0430\u043B\u044C\u043D\u044B\u0439 \u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u043A, \u0447\u0442\u043E\u0431\u044B \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u043E\u0439 \u0441\u0442\u0435\u043B\u043B\u0430\u0436 \u0434\u043B\u044F \u043A\u043D\u0438\u0433 \u0438\u043B\u0438 \u043A\u043E\u043D\u0441\u0442\u0440\u0443\u043A\u0442\u043E\u0440 \u0434\u043B\u044F \u0440\u0435\u0431\u0435\u043D\u043A\u0430. \u0410 \u0437\u0430 \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0431\u043B\u043E\u043A\u043E\u0432 \u043F\u043E 3 \u0447\u0430\u0441\u0430 \u0443\u0436\u0435 \u043C\u043E\u0436\u043D\u043E \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0441\u0435\u0440\u044C\u0435\u0437\u043D\u044B\u0439 \u043E\u0431\u044A\u0435\u043A\u0442.</li><li><strong>\u041A\u0421\u041C \u2013\xA010 000 \u0440\u0443\u0431\u043B\u0435\u0439 \u0437\u0430 8 \u0437\u0430\u043D\u044F\u0442\u0438\u0439</strong> \u041A\u0443\u0440\u0441 \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u043E\u0433\u043E \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u0442\u0432\u0430 \u0432 DIY \u0410\u043A\u0430\u0434\u0435\u043C\u0438\u0438 \u2014 \u044D\u0442\u043E \u043F\u043E\u0448\u0430\u0433\u043E\u0432\u044B\u0439 \u043A\u0443\u0440\u0441, \u0432 \u0445\u043E\u0434\u0435 \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u0432\u044B \u043F\u043E\u0437\u043D\u0430\u043A\u043E\u043C\u0438\u0442\u0435\u0441\u044C \u0441\u043E \u0432\u0441\u0435\u043C\u0438 \u044D\u0442\u0430\u043F\u0430\u043C\u0438 \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u044F \u0438\u043D\u0442\u0435\u0440\u044C\u0435\u0440\u043D\u043E\u0433\u043E \u043E\u0431\u044A\u0435\u043A\u0442\u0430 \u043E\u0442 \u044D\u0441\u043A\u0438\u0437\u0430 \u0434\u043E \u0441\u0431\u043E\u0440\u043A\u0438 \u0438 \u043E\u0442\u0434\u0435\u043B\u043A\u0438.</li><li><strong>\u0410\u0411\u041E\u041D\u0415\u041C\u0415\u041D\u0422 \u041D\u0410 \u041C\u0415\u0421\u042F\u0426 \u2013\xA015 000 \u0440\u0443\u0431\u043B\u0435\u0439</strong> \u0421\u0435\u0440\u044C\u0435\u0437\u043D\u044B\u0435 \u043F\u0440\u043E\u0435\u043A\u0442\u044B \u0442\u0440\u0435\u0431\u0443\u044E\u0442 \u0441\u0435\u0440\u044C\u0435\u0437\u043D\u043E\u0433\u043E \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u0438\u044F. \u0417\u0430 \u043C\u0435\u0441\u044F\u0446 \u0432\u0434\u0443\u043C\u0447\u0438\u0432\u043E\u0439 \u0440\u0430\u0431\u043E\u0442\u044B \u043C\u043E\u0436\u043D\u043E \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0430\u0432\u0442\u043E\u0440\u0441\u043A\u0438\u0439 \u0448\u043A\u0430\u0444, \u043D\u0435\u043E\u0431\u044B\u0447\u043D\u0443\u044E \u0434\u0432\u0443\u0441\u043F\u0430\u043B\u044C\u043D\u0443\u044E \u043A\u0440\u043E\u0432\u0430\u0442\u044C, \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0430\u0442\u044C \u0441\u0438\u0441\u0442\u0435\u043C\u0443 \u0445\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u043F\u043E\u0434 \u043E\u0441\u043E\u0431\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0441\u0432\u043E\u0435\u0433\u043E \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0430.</li><li><strong>\u0422\u0415\u041C\u0410\u0422\u0418\u0427\u0415\u0421\u041A\u0418\u0415 \u041A\u0423\u0420\u0421\u042B</strong> \u0412 \u0410\u043A\u0430\u0434\u0435\u043C\u0438\u0438 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u043F\u0440\u043E\u0445\u043E\u0434\u044F\u0442 \u043A\u0443\u0440\u0441\u044B \u0434\u043B\u044F \u0432\u0437\u0440\u043E\u0441\u043B\u044B\u0445 \u0438 \u0434\u0435\u0442\u0435\u0439, \u043D\u0430\u0447\u0438\u043D\u0430\u044E\u0449\u0438\u0445 \u0438 \u043F\u0440\u043E\u0434\u0432\u0438\u043D\u0443\u0442\u044B\u0445, \u043F\u043E \u0442\u0435\u0445\u043D\u0438\u043A\u0430\u043C \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u043E\u0433\u043E \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u0442\u0432\u0430 \u0438 \u0442\u0435\u043E\u0440\u0438\u0438 \u0434\u0438\u0437\u0430\u0439\u043D\u0430. \u041C\u044B \u0437\u043D\u0430\u0435\u043C, \u0447\u0442\u043E DIY \u043F\u0440\u0438\u043C\u0435\u043D\u0438\u043C \u0432\u0435\u0437\u0434\u0435.</li><li><strong>\u041F\u0420\u0418\u0421\u041C\u041E\u0422\u0420 \u0417\u0410 \u0414\u0415\u0422\u042C\u041C\u0418 \u2013\xA0300 \u0440\u0443\u0431\u043B\u0435\u0439 \u0432 \u0447\u0430\u0441</strong> \u0415\u0441\u043B\u0438 \u0432\u044B \u043F\u0440\u0438\u0448\u043B\u0438 \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0440\u0435\u0431\u0435\u043D\u043A\u043E\u043C, \u0442\u043E \u0443 \u0432\u0430\u0441 \u0432\u0441\u0435\u0433\u0434\u0430 \u0435\u0441\u0442\u044C \u0432\u044B\u0431\u043E\u0440 \u043F\u043E\u0440\u0430\u0431\u043E\u0442\u0430\u0442\u044C \u0432\u043C\u0435\u0441\u0442\u0435 \u0438\u043B\u0438 \u043E\u0441\u0442\u0430\u0432\u0438\u0442\u044C \u043F\u043E\u0434 \u043F\u0440\u0438\u0441\u043C\u043E\u0442\u0440\u043E\u043C \u0432 \u0434\u0435\u0442\u0441\u043A\u043E\u043C \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435. \u041C\u044B \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C \u0434\u0435\u0442\u0435\u0439 \u043E\u0442 4 \u043B\u0435\u0442.</li></ul>',8),l=[i];function s(n,d,c,_,h,p){return a(),t("div",null,l)}var m=e(r,[["render",s]]);export{g as __pageData,m as default};
